   459→static inline MagickBooleanType IsPixelEquivalent(
   460→  const Image *magick_restrict image,const Quantum *magick_restrict p,
   461→  const PixelInfo *magick_restrict q)
   462→{
   463→  MagickRealType
   464→    alpha,
   465→    beta,
   466→    value;
   467→
   468→  value=(MagickRealType) p[image->channel_map[AlphaPixelChannel].offset];
   469→  alpha=image->alpha_trait == UndefinedPixelTrait ? OpaqueAlpha : value;
   470→  beta=q->alpha_trait == UndefinedPixelTrait ? OpaqueAlpha : q->alpha;
   471→  if (AbsolutePixelValue(alpha-beta) >= MagickEpsilon)
   472→    return(MagickFalse);
   473→  if ((AbsolutePixelValue(alpha-TransparentAlpha) < MagickEpsilon) ||
   474→      (AbsolutePixelValue(beta-TransparentAlpha) < MagickEpsilon))
   475→    return(MagickTrue);  /* no color component if pixel is transparent */
   476→  value=(MagickRealType) p[image->channel_map[RedPixelChannel].offset];
   477→  if (AbsolutePixelValue(value-q->red) >= MagickEpsilon)
   478→    return(MagickFalse);
   479→  value=(MagickRealType) p[image->channel_map[GreenPixelChannel].offset];
   480→  if (AbsolutePixelValue(value-q->green) >= MagickEpsilon)
   481→    return(MagickFalse);
   482→  value=(MagickRealType) p[image->channel_map[BluePixelChannel].offset];
   483→  if (AbsolutePixelValue(value-q->blue) >= MagickEpsilon)
   484→    return(MagickFalse);
   485→  if (image->colorspace == CMYKColorspace)
   486→    {
   487→      value=(MagickRealType) p[image->channel_map[BlackPixelChannel].offset];
   488→      if (AbsolutePixelValue(value-q->black) >= MagickEpsilon)
   489→        return(MagickFalse);
   490→    }
   491→  return(MagickTrue);
   492→}
