   503→  green_blue=(MagickRealType)
   504→    pixel[image->channel_map[GreenPixelChannel].offset]-
   505→    pixel[image->channel_map[BluePixelChannel].offset];
   506→  if ((AbsolutePixelValue(red_green) < MagickEpsilon) &&
