   526→  if (AbsolutePixelValue(p->red-q->red) >= MagickEpsilon)
   527→    return(MagickFalse);
   528→  if (AbsolutePixelValue(p->green-q->green) >= MagickEpsilon)
   529→    return(MagickFalse);
