   552→  red_green=(MagickRealType) pixel[image->channel_map[RedPixelChannel].offset]-
   553→    pixel[image->channel_map[GreenPixelChannel].offset];
   554→  green_blue=(MagickRealType)
   555→    pixel[image->channel_map[GreenPixelChannel].offset]-
   556→    pixel[image->channel_map[BluePixelChannel].offset];
   557→  if ((AbsolutePixelValue(red_green) < MagickEpsilon) &&
